1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	const COMPONENT_PREMIUM = 25;
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const MAIN_ITEM_PREMIUM: Record<string, number> = {
45	  sword: 100,
46	  amulet: 60,
47	  staff: 80,
48	  potion: 40,
49	};
50	
51	const INSURANCE_VALUE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	
63	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
64	const CURSE_SURCHARGE_RATE = 0.5;
65	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
66	const HIGH_ENCHANTMENT_THRESHOLD = 5;
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_YEARS_THRESHOLD = 2;
69	const FOLLOWUP_DISCOUNT_RATE = 0.15;
70	const PROCESSING_FEE = 5;
71	const ROUNDING_PRECISION = 6;
72	
73	const componentBasePremium = (count: number): number => {
74	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
75	  return count * COMPONENT_PREMIUM;
76	};
77	
78	const COMPONENT_TYPES = ["rune", "moonstone"];
79	
80	const countByType = (items: Item[]): Map<string, number> => {
81	  const counts = new Map<string, number>();
82	  for (const { type } of items) {
83	    if (COMPONENT_TYPES.includes(type)) {
84	      counts.set(type, (counts.get(type) ?? 0) + 1);
85	    }
86	  }
87	  return counts;
88	};
89	
90	const componentsBasePremium = (items: Item[]): number => {
91	  const counts = [...countByType(items).values()];
92	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
93	};
94	
95	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
96	
97	const mainItemsBasePremium = (items: Item[]): number =>
98	  items.reduce((total, item) => total + itemBasePremium(item), 0);
99	
100	const policyBasePremium = (items: Item[]): number =>
101	  mainItemsBasePremium(items) + componentsBasePremium(items);
102	
103	const isHighEnchantment = (item: Item): boolean =>
104	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
105	
106	const itemSurcharge = (item: Item): number => {
107	  const base = itemBasePremium(item);
108	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
109	  const highEnchant = isHighEnchantment(item)
110	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
111	    : 0;
112	  return curse + highEnchant;
113	};
114	
115	const itemSurcharges = (items: Item[]): number =>
116	  items.reduce((total, item) => total + itemSurcharge(item), 0);
117	
118	const isLoyalCustomer = (customer: Customer): boolean =>
119	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
120	
121	const loyaltyDiscount = (base: number, customer: Customer): number =>
122	  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
123	
124	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
125	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
126	
127	const quotePremium = (
128	  items: Item[],
129	  customer: Customer,
130	  isFollowUp: boolean,
131	): number => {
132	  const base = policyBasePremium(items);
133	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
134	  const total =
135	    base +
136	    itemSurcharges(items) +
137	    firstInsurance -
138	    loyaltyDiscount(base, customer) -
139	    followUpDiscount(base, isFollowUp) +
140	    PROCESSING_FEE;
141	  return Math.ceil(Number(total.toFixed(ROUNDING_PRECISION)));
142	};
143	
144	const insuranceSum = (items: Item[]): number =>
145	  items.reduce((total, item) => total + (INSURANCE_VALUE[item.type] ?? 0), 0);
146	
147	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
148	
149	const claimResult = (
150	  step: ClaimStep,
151	  scenario: Scenario,
152	): { payout: number; remainingCap: number } => {
153	  const policy = scenario.steps[step.policy] as QuoteStep;
154	  const cap = CAP_MULTIPLIER * insuranceSum(policy.items);
155	  const rawPayout = step.incident.damages.reduce(
156	    (total, damage) => total + damagePayout(damage),
157	    0,
158	  );
159	  const payout = Math.min(rawPayout, cap);
160	  return { payout, remainingCap: cap - payout };
161	};
162	
163	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
164	  let quoteCount = 0;
165	  const results = scenario.steps.map((step) => {
166	    if (step.op === "claim") {
167	      return claimResult(step, scenario);
168	    }
169	    const isFollowUp = quoteCount > 0;
170	    quoteCount += 1;
171	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
172	  });
173	  return { results };
174	};
